export const meta = {
  name: 'verify-deadcode-candidates',
  description: 'Independently verify whether 3 low-coverage FLITS files are safe to delete',
  phases: [
    { title: 'Analyze', detail: 'one agent per candidate: importers, entrypoints, __main__, doc refs' },
    { title: 'Refute', detail: 'fresh agent adversarially tries to break each verdict' },
  ],
}

const REPO = '/Users/jakobfaber/Developer/repos/github.com/jakobtfaber/dsa110-FLITS'

const CANDIDATES = [
  { file: 'scattering/compare_resolutions.py', note: '0% coverage, 148 stmts, looks like a standalone script' },
  { file: 'scattering/batch_process_dsa.py', note: '0% coverage, 103 stmts, looks like a standalone script' },
  { file: 'scattering/scat_analysis/burstfit_robust.py', note: '11% coverage; CLAUDE.md documents it as sub-band consistency / leave-one-out influence — likely a live API, not dead' },
]

const VERDICT_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['file', 'verdict', 'is_runnable_script', 'has_entrypoint', 'importers', 'doc_referenced', 'evidence'],
  properties: {
    file: { type: 'string' },
    verdict: { type: 'string', enum: ['SAFE_TO_DELETE', 'KEEP', 'NEEDS_HUMAN'] },
    is_runnable_script: { type: 'boolean', description: 'has an if __name__=="__main__" block / meant to be run directly' },
    has_entrypoint: { type: 'boolean', description: 'referenced by [project.scripts]/console_scripts/entry_points' },
    importers: { type: 'array', items: { type: 'string' }, description: 'files importing this module (empty if none)' },
    doc_referenced: { type: 'boolean', description: 'named in CLAUDE.md/README/docs as a live component' },
    evidence: { type: 'string', description: 'concrete rg output lines / file findings backing the verdict' },
  },
}

const REFUTE_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['file', 'agrees_safe', 'refutation', 'final_verdict'],
  properties: {
    file: { type: 'string' },
    agrees_safe: { type: 'boolean' },
    refutation: { type: 'string', description: 'strongest reason it is NOT safe to delete, or "none found"' },
    final_verdict: { type: 'string', enum: ['SAFE_TO_DELETE', 'KEEP', 'NEEDS_HUMAN'] },
  },
}

const results = await pipeline(
  CANDIDATES,
  (c) => agent(
    `Audit whether a Python file in the FLITS repo (${REPO}) is DEAD CODE safe to delete.
Target: ${c.file}
Hint: ${c.note}

Use ripgrep (rg) and read files. Determine, with concrete evidence:
1. Static importers: search the WHOLE repo for imports of this module by dotted path (path with / -> . minus .py), relative imports (from .<name>), and 'import <basename>'.
2. Dynamic/string refs: importlib.import_module, __import__, spec_from_file_location, getattr, plugin registries, config yaml/json.
3. Entry points: any reference in pyproject.toml [project.scripts]/console_scripts/entry_points.
4. Runnable script? grep the file for 'if __name__ == "__main__"'. If present it is a user-facing CLI/script — NOT dead even at 0% test coverage; deleting removes an entry point.
5. Test refs, notebook refs.
6. Docs: named in CLAUDE.md, README, or docs/ as a live component?

SAFE_TO_DELETE only if: no importers, no dynamic refs, no entrypoint, AND not a meant-to-be-run script, AND not a documented component. If runnable-script or documented -> KEEP. If genuinely ambiguous -> NEEDS_HUMAN. Return the structured verdict with the actual rg lines as evidence.`,
    { label: `analyze:${c.file.split('/').pop()}`, phase: 'Analyze', schema: VERDICT_SCHEMA }
  ),
  (v, c) => agent(
    `ADVERSARIAL re-check of FLITS file ${c.file}. A first auditor judged verdict="${v?.verdict}".
Their findings: is_runnable_script=${v?.is_runnable_script}, has_entrypoint=${v?.has_entrypoint}, importers=${JSON.stringify(v?.importers)}, doc_referenced=${v?.doc_referenced}.
Evidence: ${v?.evidence}

Try to REFUTE a SAFE_TO_DELETE verdict. Independently re-check with rg and by reading the file. Hunt for what the first pass missed: a __main__ block making it a live script, a string/dynamic import, an indirect re-export through an __init__, a CLAUDE.md/docs mention, a sibling/script/Makefile/CI/justfile that runs or imports it. Default agrees_safe=false if ANY plausible live consumer exists.
Return whether you agree it is safe, the strongest refutation (or "none found"), and final_verdict.`,
    { label: `refute:${c.file.split('/').pop()}`, phase: 'Refute', schema: REFUTE_SCHEMA }
  ).then((rv) => ({ file: c.file, analyze: v, refute: rv }))
)

return results.filter(Boolean)

